INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-08fa-7566-949c-352ecdece9df', 'Adobe Firefly', 'Adobe Firefly é uma plataforma de inteligência artificial generativa da Adobe voltada à criação de conteúdos visuais, como imagens, ilustrações e efeitos gráficos, integrando-se ao ecossistema Creative Cloud. Suas funcionalidades incluem geração de imagens a partir de texto, preenchimento generativo e edição assistida por IA, com foco em uso comercial seguro. A complexidade é baixa a média, sendo acessível a usuários criativos sem formação técnica, não exigindo domínio de programação.', false, 'https://firefly.adobe.com', 'https://github.com/AdobeDocs/firefly-api', 'https://developer.adobe.com/firefly-services/docs/firefly-api/', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0902-732e-a39f-e50fbb99c16e', 'AllenNLP', 'AllenNLP é uma biblioteca open source desenvolvida pelo Allen Institute for AI para pesquisa e desenvolvimento em Processamento de Linguagem Natural. Oferece modelos, pipelines e componentes para tarefas como classificação de texto, análise semântica e question answering, baseados principalmente em deep learning. Possui alta complexidade e é voltada a pesquisadores e desenvolvedores, exigindo domínio de Python e frameworks como PyTorch.', true, 'https://allennlp.org', 'https://github.com/allenai/allennlp', 'https://docs.allennlp.org/', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0909-7632-8751-84bb6e9cc141', 'Alteryx', 'Alteryx é uma plataforma de analytics e ciência de dados que permite preparar, analisar e modelar dados por meio de fluxos visuais. Suas funcionalidades incluem ETL, análise preditiva e integração com ferramentas de BI, com foco em automação analítica. A complexidade é média, voltada a analistas de dados, e não exige programação obrigatória, embora permita extensões via código.', false, 'https://www.alteryx.com', 'https://github.com/alteryx/ayx-developer-sdk', 'https://www.alteryx.com', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0911-79fc-9aab-e822dfe66d92', 'Amazon Comprehend', 'Amazon Comprehend é um serviço de NLP da AWS que realiza análise automática de textos, identificando entidades, sentimentos, tópicos e idioma. É utilizado via API e integra-se facilmente a pipelines em nuvem. A complexidade é média: não exige conhecimento profundo de PLN, mas requer familiaridade com APIs e serviços cloud, especialmente se usado programaticamente.', false, 'https://aws.amazon.com/comprehend', NULL, 'https://aws.amazon.com/comprehend', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-091a-77cf-8b7c-3536c56e5ce8', 'Amazon Polly', 'Amazon Polly é um serviço de Text-to-Speech da AWS que converte texto em fala natural usando vozes neurais. Suporta múltiplos idiomas e estilos de voz, sendo amplamente usado em aplicações de acessibilidade e assistentes virtuais. A complexidade é baixa a média e pode ser utilizado sem programação via console, embora o uso avançado envolva integração por API.', false, 'https://aws.amazon.com/polly', NULL, 'https://aws.amazon.com/polly', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0924-7319-b298-8184935a364c', 'Apache OpenNLP', 'Apache OpenNLP é uma biblioteca open source para processamento de linguagem natural baseada em modelos estatísticos. Fornece funcionalidades como tokenização, POS tagging, chunking e reconhecimento de entidades nomeadas. A complexidade é alta, sendo voltada a desenvolvedores, e exige programação, geralmente em Java.', true, 'https://opennlp.apache.org', 'https://github.com/apache/opennlp', 'https://opennlp.apache.org', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-092b-70fe-806a-f2d1cd42204d', 'Apache Tika', 'Apache Tika é uma ferramenta open source para extração de texto e metadados de diversos formatos de arquivos, como PDF, DOCX e HTML. É amplamente usada em pipelines de indexação e recuperação da informação. A complexidade é média e seu uso mais avançado exige programação, embora existam interfaces de linha de comando.', true, 'https://tika.apache.org', 'https://github.com/apache/tika', 'https://tika.apache.org', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0932-7f5a-af1d-6fd018dd6390', 'Aylien Text Analysis', 'Aylien Text Analysis é uma API comercial de análise de texto que oferece funcionalidades como classificação, extração de entidades, análise de sentimento e detecção de tópicos. É utilizada principalmente em contextos corporativos e de mídia. A complexidade é média e exige integração via API, demandando conhecimento básico de programação.', false, 'https://aylien.com', NULL, 'https://aylien.com', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-093b-78a5-a949-96bcf8887380', 'Azure AI Language', 'Azure AI Language é o conjunto de serviços de linguagem natural da Microsoft Azure, oferecendo análise de sentimento, entidades, sumarização e classificação de texto. Integra-se ao ecossistema Azure e pode ser usado via portal ou API. A complexidade é média, não exigindo conhecimento profundo de PLN, mas requer familiaridade com serviços em nuvem.', false, 'https://azure.microsoft.com/en-us/products/ai-services/language', NULL, 'https://azure.microsoft.com/en-us/products/ai-services/language', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0943-75a3-99a4-655b7ca7a4d3', 'Azure AI Question Answering', 'Azure AI Question Answering é um serviço da Microsoft focado na construção de sistemas de perguntas e respostas a partir de bases textuais. Permite criar bots e assistentes informacionais com pouca configuração. A complexidade é baixa a média, podendo ser usado sem programação em interfaces gráficas, embora suporte integração via código.', false, 'https://azure.microsoft.com/en-us/products/ai-services/question-answering', NULL, 'https://azure.microsoft.com/en-us/products/ai-services/question-answering', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-094a-7249-9902-f82a221ee787', 'Bardeen', 'Bardeen é uma ferramenta de automação que utiliza IA para conectar aplicações e automatizar fluxos de trabalho repetitivos, especialmente em ambientes de produtividade digital. Suas funcionalidades incluem scraping, automação de tarefas e integração entre serviços. A complexidade é baixa e não exige programação, sendo voltada a usuários finais.', false, 'https://www.bardeen.ai', NULL, 'https://www.bardeen.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0952-7f32-9e7a-d947714299a3', 'BERT', 'BERT é um modelo de linguagem baseado em transformers desenvolvido pelo Google, projetado para compreender o contexto bidirecional de textos. É amplamente utilizado como base para tarefas de NLP como classificação e QA. A complexidade é alta, voltada a pesquisadores e desenvolvedores, exigindo domínio de programação e frameworks de deep learning.', true, 'https://github.com/google-research/bert', 'https://github.com/google-research/bert', 'https://github.com/google-research/bert', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-095a-7baf-9fe4-4683e61fae3f', 'BERTimbau', 'BERTimbau é uma adaptação do modelo BERT treinada especificamente para o português. Oferece melhor desempenho em tarefas de NLP nesse idioma, sendo amplamente usado em pesquisas e aplicações acadêmicas e industriais. A complexidade é alta e exige programação, geralmente em Python com bibliotecas como Hugging Face.', true, 'https://github.com/neuralmind-ai/portuguese-bert', 'https://github.com/neuralmind-ai/portuguese-bert', 'https://github.com/neuralmind-ai/portuguese-bert', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0962-7051-b7fe-59b8c1aaefc7', 'Brand24', 'Brand24 é uma ferramenta de monitoramento de mídias sociais e web que utiliza IA para análise de menções, sentimento e alcance de marca. É voltada a marketing e comunicação estratégica. A complexidade é baixa e não exige programação, sendo acessível por interface web.', false, 'https://brand24.com', NULL, 'https://brand24.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0968-7ff7-be10-4ad0ddcab9aa', 'CapCut', 'CapCut é um editor de vídeo que utiliza recursos de IA para edição automática, legendas, efeitos e ajustes visuais. É amplamente utilizado por criadores de conteúdo digital. A complexidade é baixa e não exige programação.', false, 'https://www.capcut.com', NULL, 'https://www.capcut.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09f0-7a63-b33f-56e7b3b8d7f8', 'DeepL Write', 'DeepL Write é uma ferramenta de assistência à escrita que utiliza IA para sugerir melhorias de estilo, clareza e correção gramatical. É voltada à produção de textos formais e profissionais. A complexidade é baixa e não exige domínio de programação.', false, 'https://www.deepl.com/write', NULL, 'https://www.deepl.com/write', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-096f-7a07-a94e-6e7dced0ff36', 'ChatGPT', 'ChatGPT é um modelo de linguagem conversacional desenvolvido pela OpenAI, projetado para gerar textos, responder perguntas, auxiliar em programação e apoiar tarefas cognitivas complexas. Pode ser usado via interface web ou API. A complexidade varia de baixa a alta, não exigindo programação para uso básico, mas permitindo integrações avançadas via código.', false, 'https://chat.openai.com', NULL, 'https://chat.openai.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0976-7f9d-bf2b-8c9405c21193', 'ClaudeAI', 'ClaudeAI é um modelo de linguagem desenvolvido pela Anthropic, focado em segurança, coerência e uso ético da IA generativa. É utilizado para conversação, análise textual e geração de conteúdo. A complexidade é semelhante ao ChatGPT, não exigindo programação para uso direto, mas suportando integração via API.', false, 'https://claude.ai', NULL, 'https://claude.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-097d-7ac1-ae01-9d4b2d5766b2', 'Clean Email', 'Clean Email é uma ferramenta de organização e limpeza de caixas de e-mail que utiliza automação e regras inteligentes para gerenciamento de mensagens. É voltada a produtividade pessoal. A complexidade é baixa e não exige programação.', false, 'https://clean.email', NULL, 'https://clean.email', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0984-7279-888b-081cef3f0532', 'Cleanup.pictures', 'Cleanup.pictures é uma ferramenta baseada em IA para remoção automática de objetos e imperfeições em imagens. É amplamente usada em design e edição visual rápida. A complexidade é baixa e não exige programação.', false, 'https://cleanup.pictures', NULL, 'https://cleanup.pictures', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-098b-79fb-b42f-580e9d21b69d', 'CMDH (Linux)', 'CMDH refere-se ao uso de comandos de help e documentação no ambiente Linux, auxiliando na compreensão de comandos e sistemas. Sua complexidade é média, voltada a usuários com familiaridade em sistemas operacionais, exigindo conhecimento de linha de comando.', false, 'https://github.com/smallwat3r/cmdh', 'https://github.com/smallwat3r/cmdh', 'https://github.com/smallwat3r/cmdh', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0991-7774-93ea-b9260d064d37', 'Cocounsel AI', 'Cocounsel AI é uma ferramenta de IA voltada ao apoio jurídico, auxiliando na análise de documentos, pesquisa legal e geração de textos jurídicos. A complexidade é média, direcionada a profissionais do Direito, não exigindo programação.', false, 'https://www.cocounsel.ai', NULL, 'https://www.cocounsel.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0997-7a17-b61b-d3689ba0fd3a', 'Codeium', 'Codeium é uma ferramenta de assistência à programação baseada em IA que sugere código, completa funções e auxilia no desenvolvimento de software. Integra-se a IDEs populares. A complexidade é média e é voltada a desenvolvedores, exigindo conhecimento de programação.', true, 'https://codeium.com', NULL, 'https://codeium.com', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-099d-71db-9b94-bc64de553b58', 'CodeT5', 'CodeT5 é um modelo baseado em transformers para tarefas de entendimento e geração de código, como sumarização e tradução entre linguagens. É utilizado em pesquisa e desenvolvimento de ferramentas de programação assistida. A complexidade é alta e exige programação e conhecimento em machine learning.', true, 'https://github.com/salesforce/CodeT5', 'https://github.com/salesforce/CodeT5', 'https://github.com/salesforce/CodeT5', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09a2-7d4c-8672-fe1490821235', 'CodeWhisperer (AWS)', 'CodeWhisperer é um assistente de programação da AWS que sugere código em tempo real com base no contexto do desenvolvedor. Integra-se a IDEs e serviços cloud. A complexidade é média e exige domínio de programação.', true, 'https://aws.amazon.com/codewhisperer', NULL, 'https://aws.amazon.com/codewhisperer', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09a8-7575-a1e3-ce4666f3dab2', 'CogCompNLP', 'CogCompNLP é um conjunto de ferramentas de NLP desenvolvido pela Universidade de Illinois, focado em análise semântica profunda. Inclui parsers, NER e modelos de inferência. A complexidade é alta e exige programação avançada.', true, 'https://github.com/CogComp/cogcomp-nlp', 'https://github.com/allenai/allennlp', 'https://github.com/CogComp/cogcomp-nlp', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09ae-70a4-8d25-0940c95c9e7c', 'Colibri Core', 'Colibri Core é uma plataforma de NLP voltada à análise textual e extração de conhecimento, com foco em aplicações corporativas. Suas funcionalidades incluem mineração de texto e análise semântica. A complexidade é média e geralmente não exige programação para uso básico.', true, 'https://colibricore.readthedocs.io', NULL, 'https://colibricore.readthedocs.io', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09b6-715c-9aa5-018a8ef2dd2a', 'Convert Case', 'Convert Case é uma ferramenta simples para conversão de texto entre diferentes formatos de capitalização. É voltada a produtividade textual. A complexidade é baixa e não exige programação.', false, 'https://convertcase.net', NULL, 'https://convertcase.net', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09be-78e2-8a99-d4ff667827a7', 'CoreNLP', 'CoreNLP é o conjunto de ferramentas de NLP da Universidade de Stanford, oferecendo análise sintática, semântica e extração de entidades. É amplamente usado em pesquisa acadêmica. A complexidade é alta e exige programação, geralmente em Java ou via APIs.', true, 'https://stanfordnlp.github.io/CoreNLP', 'https://github.com/apache/corenlp', 'https://stanfordnlp.github.io/CoreNLP', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09c6-7ffb-8183-73739a68e6e0', 'Correção', 'Correção refere-se a ferramentas de correção ortográfica e gramatical assistidas por IA, voltadas à revisão textual. A complexidade é baixa e não exige programação.', false, 'https://www.corrector.co', NULL, 'https://www.corrector.co', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09cd-75c1-8c96-bef1b0af94fd', 'CSTParser', 'CSTParser é uma ferramenta de análise sintática baseada na teoria de Constituent Structure Trees, usada em pesquisas linguísticas. A complexidade é alta e exige conhecimento técnico e programação.', true, 'https://github.com/own-pt/cstparser', NULL, 'https://github.com/own-pt/cstparser', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09d4-7680-8a2b-60cd71a5854b', 'Cut (Linux)', 'Cut é um comando do Linux usado para extração de colunas e segmentos de texto em arquivos. É amplamente utilizado em processamento de dados em linha de comando. A complexidade é média e exige conhecimento básico de shell scripting.', true, 'https://man7.org/linux/man-pages/man1/cut.1.html', NULL, 'https://man7.org/linux/man-pages/man1/cut.1.html', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09db-7ec2-856b-0cfc2dfa0ad2', 'DALL-E 3 (OpenAI)', 'DALL-E 3 é um modelo de inteligência artificial generativa desenvolvido pela OpenAI para criação de imagens a partir de descrições textuais. Permite gerar ilustrações, artes conceituais e imagens realistas com alto grau de aderência semântica ao prompt. A complexidade é baixa para uso via interface conversacional e média quando integrado via API, não exigindo programação para uso básico, mas permitindo automação programática.', false, 'https://chat.openai.com', NULL, 'https://chat.openai.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09e2-79fe-850c-7531e73e4ba4', 'Deep Dream Generator (Google AI)', 'Deep Dream Generator é uma ferramenta de geração e transformação de imagens baseada em redes neurais profundas, conhecida por criar efeitos visuais oníricos e estilizados. Suas funcionalidades incluem aplicação de estilos artísticos e intensificação de padrões visuais. A complexidade é baixa e não exige programação, sendo acessível por interface web.', false, 'https://deepdreamgenerator.com', NULL, 'https://deepdreamgenerator.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09e9-74fb-870c-30d7a23d3a52', 'DeepL', 'DeepL é um sistema de tradução automática neural reconhecido pela alta qualidade semântica e fluidez dos textos traduzidos. Suporta múltiplos idiomas e é amplamente utilizado em contextos acadêmicos e profissionais. A complexidade é baixa, não exigindo programação para uso via interface, embora ofereça API para integração em sistemas.', false, 'https://www.deepl.com', NULL, 'https://www.deepl.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09f7-7762-bc62-7fa8e5d2e279', 'DeepPavlov', 'DeepPavlov é uma biblioteca open source para construção de sistemas conversacionais e aplicações de NLP, oferecendo modelos prontos para chatbots, QA e NLU. É baseada em deep learning e amplamente utilizada em pesquisa e produção. A complexidade é alta e exige domínio de programação em Python e frameworks de machine learning.', true, 'https://deeppavlov.ai', 'https://github.com/deepmipt/DeepPavlov', 'https://deeppavlov.ai', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-09ff-7548-b67b-b1975b9f75c3', 'Deepseek', 'Deepseek é uma família de modelos de linguagem e ferramentas de IA generativa voltadas à compreensão e geração de texto e código. É utilizada tanto para pesquisa quanto para aplicações práticas de LLMs. A complexidade varia de média a alta, não exigindo programação para uso via interface, mas demandando conhecimento técnico para integrações avançadas.', false, 'https://deepseek.com', NULL, 'https://deepseek.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a06-73b1-b032-905c1e66ce81', 'Dream by Wombo', 'Dream by Wombo é uma aplicação de geração de imagens por IA focada em arte estilizada a partir de prompts textuais. É amplamente usada por usuários criativos sem formação técnica. A complexidade é baixa e não exige programação.', false, 'https://www.wombo.art', NULL, 'https://www.wombo.art', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a0d-7306-999e-b3c3e91e1a7f', 'Drift', 'Drift é uma plataforma de automação de marketing conversacional que utiliza chatbots e IA para engajamento com clientes, geração de leads e suporte. Integra-se a sistemas de CRM e marketing digital. A complexidade é média e não exige programação para configuração básica.', false, 'https://www.drift.com', NULL, 'https://www.drift.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a13-7a78-881f-9e9970ce1019', 'EditPad', 'EditPad é um editor de texto avançado voltado à escrita, edição e manipulação de grandes volumes de texto. Inclui recursos de busca, regex e organização textual. A complexidade é baixa a média e não exige programação, embora seja útil para usuários técnicos.', false, 'https://www.editpad.org', NULL, 'https://www.editpad.org', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a1a-788e-9370-d1aaaf4f599a', 'elai.io', 'elai.io é uma plataforma de geração de vídeos por IA que converte textos em vídeos com avatares virtuais e narração automática. É utilizada em treinamento corporativo e marketing educacional. A complexidade é baixa e não exige programação.', false, 'https://elai.io', NULL, 'https://elai.io', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a21-7cbf-addc-676d71c08502', 'Embedding Projector', 'Embedding Projector é uma ferramenta visual, popularizada pelo TensorFlow, para exploração e visualização de embeddings vetoriais em espaços de alta dimensionalidade. É amplamente usada para análise semântica e interpretação de modelos. A complexidade é média e não exige programação para uso básico, embora seja frequentemente usada por pesquisadores.', true, 'https://projector.tensorflow.org', 'https://github.com/tensorflow/embedding-projector', 'https://projector.tensorflow.org', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a28-757d-a6f4-ca9f8f9fd653', 'Enelvo', 'Enelvo é uma ferramenta de normalização textual para o português, focada em correção de variações ortográficas e ruídos comuns em textos informais. É utilizada em pré-processamento de dados para NLP. A complexidade é média e exige programação para integração em pipelines.', true, 'https://github.com/nilc-enelvo/enelvo', 'https://github.com/nilc-enelvo/enelvo', 'https://github.com/nilc-enelvo/enelvo', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a2e-759c-8659-a285beb17d75', 'Fairseq', 'Fairseq é uma biblioteca open source do Meta AI para treinamento de modelos de sequência, especialmente em tradução automática e geração de texto. Baseia-se em deep learning e transformers. A complexidade é alta e exige forte domínio de programação e machine learning.', true, 'https://fairseq.readthedocs.io', 'https://github.com/facebookresearch/fairseq', 'https://fairseq.readthedocs.io', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a34-729d-8a80-3cac7a93166e', 'Fake.Br', 'Fake.Br é um conjunto de ferramentas e recursos voltados à detecção de fake news em língua portuguesa, usado principalmente em pesquisa acadêmica. Inclui bases de dados e modelos de classificação textual. A complexidade é média a alta e exige programação para uso efetivo.', true, 'https://github.com/roneysco/Fake.br-Corpus', 'https://github.com/roneysco/Fake.br-Corpus', 'https://github.com/roneysco/Fake.br-Corpus', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a3b-70c9-91e6-67b579534532', 'FastText', 'FastText é uma biblioteca desenvolvida pelo Facebook AI para representação vetorial de palavras e classificação de texto, conhecida por sua eficiência e suporte a subpalavras. É amplamente usada em tarefas de NLP clássicas. A complexidade é média e exige programação, geralmente em Python ou C++.', true, 'https://fasttext.cc', 'https://github.com/facebookresearch/fastText', 'https://fasttext.cc', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a41-7d5f-af63-9bab27893fbe', 'FireCrawl', 'FireCrawl é uma ferramenta de coleta e rastreamento de conteúdos web voltada à extração estruturada de dados textuais para análise e indexação. É usada em pipelines de dados e recuperação da informação. A complexidade é média e geralmente exige programação para integração.', true, 'https://firecrawl.dev', NULL, 'https://firecrawl.dev', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a47-7f00-81bd-3abf7ae16983', 'Flair AI', 'Flair AI é uma biblioteca de NLP que oferece embeddings contextuais e modelos para tarefas como NER, POS tagging e classificação de texto. É voltada a pesquisadores e desenvolvedores. A complexidade é alta e exige programação em Python.', false, 'https://flair.ai', 'https://github.com/flairNLP/flair', 'https://flair.ai', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a4f-759f-850a-cd54c3e3309b', 'Galileo AI', 'Galileo AI é uma ferramenta de geração automática de interfaces e layouts a partir de descrições textuais, utilizando IA generativa para design de produtos digitais. A complexidade é baixa a média e não exige programação para uso básico.', false, 'https://www.rungalileo.io', NULL, 'https://www.rungalileo.io', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a55-7afc-b30f-456510479443', 'Gamma.app', 'Gamma.app é uma plataforma de criação de apresentações e documentos assistida por IA, permitindo gerar conteúdos estruturados a partir de prompts. É voltada à produtividade e comunicação visual. A complexidade é baixa e não exige programação.', false, 'https://gamma.app', NULL, 'https://gamma.app', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a5c-711b-809c-1e73bed7b106', 'Gemini (Google)', 'Gemini é a família de modelos de linguagem multimodais do Google, projetada para compreensão e geração de texto, código, imagens e outros tipos de dados. Pode ser utilizada via interfaces conversacionais ou APIs. A complexidade varia de baixa a alta, não exigindo programação para uso direto, mas permitindo integrações avançadas.', false, 'https://gemini.google.com', NULL, 'https://gemini.google.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a63-7e7f-8e64-febe41b52f2d', 'Gensim', 'Gensim é uma biblioteca open source para modelagem de tópicos e representação semântica de textos, conhecida por implementações de LDA, Word2Vec e Doc2Vec. É amplamente usada em pesquisa e aplicações de NLP. A complexidade é média a alta e exige programação em Python.', true, 'https://radimrehurek.com/gensim', 'https://github.com/RaRe-Technologies/gensim', 'https://radimrehurek.com/gensim', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a6a-7e75-9473-f84ff1a8b5b0', 'Ginger Software', 'Ginger Software é uma ferramenta de correção gramatical e sugestão de escrita baseada em IA, voltada à melhoria da clareza textual. É utilizada por estudantes e profissionais. A complexidade é baixa e não exige programação.', false, 'https://www.gingersoftware.com', NULL, 'https://www.gingersoftware.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a72-7636-9662-6710519313f1', 'GitHub Copilot', 'GitHub Copilot é um assistente de programação baseado em IA que sugere código em tempo real diretamente no editor, auxiliando no desenvolvimento de software. É integrado a IDEs populares. A complexidade é média e exige domínio de programação.', true, 'https://github.com/features/copilot', 'https://github.com/features/copilot', 'https://github.com/features/copilot', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a79-7fc1-abd8-594b74d06d33', 'GloVe (Global Vectors)', 'GloVe é um modelo de representação vetorial de palavras baseado em estatísticas globais de coocorrência. É amplamente utilizado em NLP clássico como alternativa ao Word2Vec. A complexidade é média e exige programação para uso em pipelines.', true, 'https://nlp.stanford.edu/projects/glove', 'https://github.com/stanfordnlp/GloVe', 'https://nlp.stanford.edu/projects/glove', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a80-7e80-9e67-b3cbfb955d97', 'Google Cloud Natural Language API', 'Google Cloud Natural Language API é um serviço de NLP que oferece análise de sentimento, entidades, sintaxe e classificação de texto via API. É integrado ao ecossistema Google Cloud. A complexidade é média e exige conhecimento básico de programação para integração.', false, 'https://cloud.google.com/natural-language', NULL, 'https://cloud.google.com/natural-language', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a87-749c-abe7-90c6aea8f114', 'Google Tradutor', 'Google Tradutor é um serviço de tradução automática que utiliza modelos neurais para conversão entre idiomas. É amplamente utilizado por usuários finais e profissionais. A complexidade é baixa e não exige programação, embora possua API para uso programático.', false, 'https://translate.google.com', NULL, 'https://translate.google.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a8e-7d2a-be18-22a2940b9bfd', 'GPT CLI (Linux)', 'GPT CLI é uma interface de linha de comando que permite interagir com modelos de linguagem diretamente no ambiente Linux. É utilizada para automação, geração de texto e apoio a tarefas técnicas. A complexidade é média e exige familiaridade com linha de comando e configuração técnica.', true, 'https://github.com/madawei2699/gptcli', 'https://github.com/madawei2699/gptcli', 'https://github.com/madawei2699/gptcli', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a95-7f46-9866-f824fffabb24', 'Grammarly', 'Grammarly é uma ferramenta de assistência à escrita que utiliza inteligência artificial para correção gramatical, ortográfica, estilística e de tom. É amplamente usada em contextos acadêmicos e profissionais para aprimorar a clareza textual. A complexidade é baixa e não exige domínio de programação.', false, 'https://www.grammarly.com', NULL, 'https://www.grammarly.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0a9d-77c0-9583-286ee68aec60', 'GravityWrite', 'GravityWrite é uma plataforma de geração de conteúdo por IA voltada à escrita de textos de marketing, blogs e descrições comerciais. Oferece templates e geração automática baseada em prompts. A complexidade é baixa e não exige programação.', false, 'https://gravitywrite.com', NULL, 'https://gravitywrite.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0aa5-7a1f-8b6b-eea1a8e2de59', 'Grep (Linux)', 'Grep é um comando do sistema Linux utilizado para busca e filtragem de padrões textuais em arquivos. É fundamental em pipelines de processamento de texto e análise de logs. A complexidade é média e exige conhecimento de linha de comando, não sendo voltado a usuários sem perfil técnico.', true, 'https://man7.org/linux/man-pages/man1/grep.1.html', NULL, 'https://man7.org/linux/man-pages/man1/grep.1.html', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0aac-7535-b4e0-6220e4ee5ab4', 'GroupDocs', 'GroupDocs é um conjunto de APIs e ferramentas para manipulação, conversão e análise de documentos em múltiplos formatos. É utilizado em contextos corporativos para automação documental. A complexidade é média e geralmente exige programação para integração.', false, 'https://products.groupdocs.com', NULL, 'https://products.groupdocs.com', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ab3-7662-9342-b35c58622c93', 'Grover AI', 'Grover AI é um modelo de linguagem desenvolvido para geração e detecção de textos sintéticos, especialmente notícias falsas. É amplamente usado em pesquisa sobre desinformação. A complexidade é alta e exige programação e conhecimento em machine learning.', false, 'https://grover.allenai.org', NULL, 'https://grover.allenai.org', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ab9-789c-9668-439d54f658c4', 'Haystack (da deepset)', 'Haystack é um framework open source para construção de sistemas de busca semântica, question answering e RAG baseados em NLP. Integra modelos de linguagem, vetorização e bancos de dados vetoriais. A complexidade é alta e exige domínio de programação em Python.', true, 'https://haystack.deepset.ai', 'https://github.com/deepset-ai/haystack', 'https://haystack.deepset.ai', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ac1-7eb5-b033-ace5a5b2042c', 'Hemingway Editor', 'Hemingway Editor é uma ferramenta de apoio à escrita que avalia legibilidade, clareza e complexidade textual, sugerindo simplificações. É voltada a escritores e comunicadores. A complexidade é baixa e não exige programação.', false, 'https://hemingwayapp.com', NULL, 'https://hemingwayapp.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0aca-705d-8c6f-d4e47b312a36', 'Hugging Face', 'Hugging Face é uma plataforma e comunidade dedicada ao compartilhamento de modelos, datasets e ferramentas de machine learning, especialmente em NLP. Oferece repositórios, APIs e interfaces de uso direto. A complexidade varia de baixa a alta, não exigindo programação para uso exploratório, mas sendo essencial para desenvolvedores e pesquisadores.', true, 'https://huggingface.co', 'https://github.com/huggingface', 'https://huggingface.co', 2);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ad2-769b-b6e1-f70fd54becd2', 'Hugging Face Transformers', 'Hugging Face Transformers é uma biblioteca open source que fornece implementações de modelos de linguagem baseados em transformers, como BERT e GPT. É amplamente utilizada em pesquisa e produção. A complexidade é alta e exige domínio de programação em Python.', true, 'https://huggingface.co/transformers', 'https://github.com/huggingface/transformers', 'https://huggingface.co/docs/transformers/installation', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ad9-7483-9275-8d77663d7dcc', 'Ideamap.ia', 'Ideamap.ia é uma ferramenta de ideação assistida por IA que auxilia na geração e organização de ideias para projetos criativos e estratégicos. É voltada à inovação e brainstorming. A complexidade é baixa e não exige programação.', false, 'https://ideamap.ai', NULL, 'https://ideamap.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0ae3-7c0c-b70a-49bb7d613c84', 'INCEPTION', 'INCEPTION é uma arquitetura de redes neurais convolucionais desenvolvida para visão computacional, amplamente usada em classificação de imagens. É utilizada em pesquisa e aplicações avançadas de deep learning. A complexidade é alta e exige programação e conhecimento em redes neurais.', true, 'https://inception-project.github.io', NULL, 'https://inception-project.github.io', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0aeb-785a-8e60-dc88353f6adb', 'IRAMUTEQ', 'IRAMUTEQ é um software para análise estatística de textos que utiliza métodos como classificação hierárquica descendente e análise de similitude. É amplamente usado em pesquisas qualitativas nas ciências humanas. A complexidade é média, exigindo conhecimento metodológico, mas não programação direta.', false, 'http://www.iramuteq.org', NULL, 'http://www.iramuteq.org', 3);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0af3-71d6-a41d-f6d1e87e2d9c', 'Jetpack', 'Jetpack é um conjunto de ferramentas para WordPress que inclui automação, segurança, análise de tráfego e assistência à criação de conteúdo. É voltado a gestores de sites e criadores digitais. A complexidade é baixa e não exige programação.', false, 'https://jetpack.com', NULL, 'https://jetpack.com', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0afc-7b12-9fc9-0f972dddb121', 'Kaiber', 'Kaiber é uma plataforma de geração de vídeos por IA que transforma imagens e textos em animações estilizadas. É utilizada por criadores de conteúdo e artistas digitais. A complexidade é baixa e não exige programação.', false, 'https://kaiber.ai', NULL, 'https://kaiber.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0b04-77d2-8ecb-67d31fae2b9b', 'KerasNLP', 'KerasNLP é uma biblioteca de NLP integrada ao ecossistema Keras, oferecendo modelos e pipelines prontos para tarefas de linguagem natural. É voltada a desenvolvedores e pesquisadores. A complexidade é média a alta e exige programação em Python.', true, 'https://keras.io/keras_nlp', 'https://github.com/keras-team/keras-nlp', 'https://keras.io/keras_nlp', 4);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0b0a-7eeb-aaf4-73a76e3f1342', 'KOMO', 'KOMO é uma ferramenta de busca e resposta baseada em IA que combina recuperação de informação e geração de texto para responder perguntas complexas. É voltada a usuários finais e profissionais do conhecimento. A complexidade é baixa e não exige programação.', false, 'https://www.komo.ai', NULL, 'https://www.komo.ai', 1);
INSERT INTO harmonia.tool (tool_uuidv7, tool_name, tool_description, tool_data_prog, tool_official_link, tool_repository_link, tool_documentation_link, tool_complexity) VALUES ('019c7b2c-0b13-7677-ba9d-63a243c71d24', 'LanguageTool', 'LanguageTool é uma ferramenta open source de correção gramatical e estilística que suporta múltiplos idiomas. Pode ser usada via interface web ou integrada a editores. A complexidade é baixa e não exige programação para uso básico.', false, 'https://languagetool.org', 'https://github.com/languagetool-org/languagetool', 'https://languagetool.org', 1);
